import pandas as pd
import numpy as np
import json, os, base64
import warnings
warnings.filterwarnings('ignore')
print('✅ Libraries ready.')

DATA_URL = 'https://raw.githubusercontent.com/owid/co2-data/master/owid-co2-data.csv'

AGGREGATES = [
    'World', 'Africa', 'Asia', 'Europe', 'North America', 'South America',
    'Oceania', 'European Union (27)', 'European Union (28)',
    'High-income countries', 'Low-income countries',
    'Lower-middle-income countries', 'Upper-middle-income countries',
    'OECD (Eora)', 'Non-OECD (Eora)', 'Asia (excl. China & India)',
    'Europe (excl. EU-27)', 'Europe (excl. EU-28)',
    'North America (excl. USA)', 'International transport', 'Antarctica',
]

print('⏳ Downloading data...')
raw = pd.read_csv(DATA_URL)

cols = ['country', 'iso_code', 'year', 'co2', 'consumption_co2', 'population', 'gdp']
KEY = [c for c in cols if c in raw.columns]
df = (
    raw[KEY]
    .query('country not in @AGGREGATES')
    .dropna(subset=['co2', 'consumption_co2', 'population', 'iso_code'])
    .query('population >= 1_000_000')
    .copy()
)

# Core Metrics
df['outsourced'] = df['consumption_co2'] - df['co2']
df['outsourced_per_capita'] = (df['outsourced'] / df['population']) * 1e6
df['co2_per_capita'] = (df['co2'] / df['population']) * 1e6
df['consumption_per_cap'] = (df['consumption_co2'] / df['population']) * 1e6
df['pop_millions'] = df['population'] / 1e6

if 'gdp' in df.columns:
    df['gdp_per_cap'] = df['gdp'] / df['population']
    df['co2_intensity'] = df['co2'] / (df['gdp'] / 1e9)
else:
    df['gdp_per_cap'] = 0
    df['co2_intensity'] = df['co2_per_capita']

# Baseline 2007 comparisons
df_2007 = df[df['year'] == 2007].set_index('country')[['co2', 'consumption_co2', 'co2_intensity']]
df_2007.columns = ['co2_2007', 'cons_2007', 'intensity_2007']
df = df.merge(df_2007, on='country', how='left')

# Decoupling Score (Change in intensity)
df['intensity_change'] = (df['co2_intensity'] - df['intensity_2007']) / df['intensity_2007'].replace(0, np.nan) * 100
df['intensity_change'] = df['intensity_change'].fillna(0)

# Hidden Emissions / Greenwashing Logic
df['prod_change'] = (df['co2'] - df['co2_2007']) / df['co2_2007'].replace(0, np.nan) * 100
df['cons_change'] = (df['consumption_co2'] - df['cons_2007']) / df['cons_2007'].replace(0, np.nan) * 100
df['greenwashing_score'] = df['cons_change'].fillna(0) - df['prod_change'].fillna(0)
df['hidden_emissions_flag'] = (df['prod_change'] < -5) & (df['cons_change'] >= 0)

# Accountability Score
def normalize(series):
    return (series - series.min()) / (series.max() - series.min()) * 100

resp = normalize(df['consumption_per_cap']) * 0.4 + normalize(df['outsourced_per_capita']) * 0.3
if 'gdp' in df.columns:
    resp += normalize(df['gdp_per_cap']) * 0.3
else:
    resp += normalize(df['co2_per_capita']) * 0.3

df['accountability_score'] = resp + df['prod_change'].fillna(0).clip(upper=0) * 0.5
df['accountability_score'] = normalize(df['accountability_score']).round(1)

years = sorted(df['year'].unique())
print(f'✅ {len(df):,} country-year rows | {len(years)} years: {years[0]}–{years[-1]}')

print('Building JSON...')
data_by_year = {}
for yr in years:
    ydf = df[df['year'] == yr]
    records = []
    for _, row in ydf.iterrows():
        records.append({
            'country': row['country'],
            'iso_code': row['iso_code'],
            'co2': round(float(row['co2']), 1),
            'consumption_co2': round(float(row['consumption_co2']), 1),
            'outsourced': round(float(row['outsourced']), 1),
            'outsourced_per_capita': round(float(row['outsourced_per_capita']), 3),
            'co2_per_capita': round(float(row['co2_per_capita']), 2),
            'consumption_per_cap': round(float(row['consumption_per_cap']), 2),
            'pop_millions': round(float(row['pop_millions']), 1),
            'intensity_change': round(float(row['intensity_change']), 1),
            'prod_change': round(float(row['prod_change']), 1),
            'cons_change': round(float(row['cons_change']), 1),
            'greenwashing_score': round(float(row['greenwashing_score']), 1),
            'is_hidden': bool(row['hidden_emissions_flag']),
            'accountability_score': round(float(row['accountability_score']), 1),
        })
    data_by_year[str(yr)] = records

DATA_JSON = json.dumps(data_by_year, separators=(',', ':'))
YEARS_JSON = json.dumps([str(y) for y in years])

TEMPLATE_B64 = ''
template = base64.b64decode(TEMPLATE_B64).decode('utf-8')

html = template.replace('$$PLOTLY_DATA$$', DATA_JSON).replace('$$PLOTLY_YEARS$$', YEARS_JSON)
out_file = 'Illusion_of_Climate_Progress_Dashboard.html'
with open(out_file, 'w', encoding='utf-8') as f:
    f.write(html)
print(f'✅ Saved dashboard: {out_file}')

try:
    from google.colab import files
    files.download(out_file)
    print('📦 Download started.')
except ImportError:
    pass




